import assert from 'node:assert';
import {
  PATTERN_HORIZON_COMPILER_THEOREM_IDS,
  admitPatternHorizonProgram,
  compilePatternHorizonWindows,
  compilePatternHorizonProgram,
  derivePatternHorizonCompiler,
  type PatternHorizonCompilerInput,
  type PatternHorizonObservationAuthorityInput,
} from '../lib';
import { JUGGLING_CHAOS_ORCHESTRATION_THEOREM_IDS } from '../juggling-chaos-orchestration';
import { JUGGLING_ORBIT_THEOREM_IDS } from '../juggling-orbit-formalization';
import { CERTIFIED_ALLOCATION_KERNEL_THEOREM_IDS } from '../certified-allocation-kernel';

const READY_AUTHORITY: PatternHorizonObservationAuthorityInput = {
  plan: {
    pointIds: ['center'],
    samplesPerPoint: 1,
    maxAttemptsPerPoint: 1,
  },
  points: [
    {
      pointId: 'center',
      accepted: 1,
      rejected: 0,
      observed: 1,
    },
  ],
  modelSolved: true,
  frame: {
    gazePoint: { x: 500, y: 500 },
    zone: 'unavailable',
    confidenceScore: 900,
    confidenceFloor: 600,
  },
  budget: {
    deadlineMs: 5,
    elapsedMs: 1,
  },
};

const DIRECT_INPUT: PatternHorizonCompilerInput = {
  kind: 'direct',
  generatedAt: '2026-04-11T00:00:00.000Z',
  source: 'test-suite',
  phaseBeat: 0,
  horizonBeats: 2,
  catchToleranceBeats: 0.25,
  observationAuthority: READY_AUTHORITY,
  orbit: {
    period: 2,
    throws: [
      { beat: 0, fromHand: 'right', flightBeats: 3 },
      { beat: 1, fromHand: 'left', flightBeats: 3 },
    ],
  },
};

const directA = derivePatternHorizonCompiler(DIRECT_INPUT);
const directB = derivePatternHorizonCompiler(DIRECT_INPUT);
const directProgram = compilePatternHorizonProgram(DIRECT_INPUT);
const directAdmission = admitPatternHorizonProgram(
  directProgram,
  READY_AUTHORITY
);

assert.deepStrictEqual(directA, directB);
assert.strictEqual(directA.generatedAt, '2026-04-11T00:00:00.000Z');
assert.strictEqual(directA.source, 'test-suite');
assert.strictEqual(directA.activePattern.kind, 'direct');
assert.strictEqual(directA.aggregate.totalWindowCount, 2);
assert.strictEqual(directA.aggregate.admissibleWindowCount, 2);
assert.strictEqual(directA.aggregate.candidateCount, 2);
assert.strictEqual(directA.aggregate.observationReady, true);
assert.strictEqual(directA.aggregate.committed, true);
assert.strictEqual(directA.policy, 'commit-primary');
assert.deepStrictEqual(directA.authority.decision, {
  kind: 'allocate',
  candidateId: 1,
});
assert.strictEqual(directA.selectedWindow?.catchBeatOffset, 0);
assert.strictEqual(directA.selectedWindow?.fromHand, 'left');
assert.strictEqual(directProgram.frontier.length, 2);
assert.strictEqual(directProgram.frontier[0]?.slot, 0);
assert.strictEqual(
  directProgram.frontier[0]?.window.windowId,
  directA.selectedWindow?.windowId
);
assert.deepStrictEqual(directAdmission.authority.decision, {
  kind: 'allocate',
  candidateId: 0,
});
assert.strictEqual(directAdmission.selectedSlot, 0);
assert.strictEqual(
  directAdmission.selectedWindow?.windowId,
  directProgram.frontier[0]?.window.windowId
);
assert.strictEqual(directAdmission.policy, 'commit-primary');

for (const theoremId of PATTERN_HORIZON_COMPILER_THEOREM_IDS) {
  assert.ok(directA.theoremIds.includes(theoremId));
}
assert.deepStrictEqual(
  directA.dependentTheoremIds.orbit,
  JUGGLING_ORBIT_THEOREM_IDS
);
assert.deepStrictEqual(
  directA.dependentTheoremIds.allocation,
  CERTIFIED_ALLOCATION_KERNEL_THEOREM_IDS
);
assert.deepStrictEqual(directA.dependentTheoremIds.composition, []);

const windowProjection = compilePatternHorizonWindows(
  directA.orbit,
  0,
  1,
  0.25,
  false
);
assert.strictEqual(windowProjection.length, 2);
assert.strictEqual(windowProjection[0]?.candidateId, 1);
assert.strictEqual(windowProjection[1]?.suppressionReason, 'outside-horizon');

const MACHINE_ONLY_PATTERN: PatternHorizonCompilerInput = {
  kind: 'direct',
  generatedAt: '2026-04-11T00:00:00.000Z',
  source: 'test-suite',
  phaseBeat: 0,
  horizonBeats: 2,
  catchToleranceBeats: 0.25,
  observationAuthority: READY_AUTHORITY,
  orbit: {
    period: 2,
    throws: [
      { beat: 0, fromHand: 'right', flightBeats: 2, angleDeg: 0, speed: 3 },
      { beat: 0, fromHand: 'right', flightBeats: 3, angleDeg: 45, speed: 8 },
      { beat: 1, fromHand: 'left', flightBeats: 2 },
    ],
    machineOnlyMultiplexThreshold: 2,
    machineOnlyAngleThresholdDeg: 12,
    machineOnlySpeedRatioThreshold: 1.3,
  },
};

const machineBlocked = derivePatternHorizonCompiler(MACHINE_ONLY_PATTERN);
assert.strictEqual(machineBlocked.aggregate.totalWindowCount, 3);
assert.strictEqual(machineBlocked.aggregate.suppressedMachineOnlyCount, 2);
assert.strictEqual(machineBlocked.aggregate.candidateCount, 1);
assert.strictEqual(
  machineBlocked.windows.filter(
    (window) => window.suppressionReason === 'machine-only'
  ).length,
  2
);

const machineAllowed = derivePatternHorizonCompiler({
  ...MACHINE_ONLY_PATTERN,
  allowMachineOnly: true,
});
assert.strictEqual(machineAllowed.aggregate.suppressedMachineOnlyCount, 0);
assert.strictEqual(machineAllowed.aggregate.candidateCount, 3);
assert.strictEqual(machineAllowed.selectedWindow?.machineOnlyCandidate, true);
assert.strictEqual(machineAllowed.policy, 'escalate-machine-only');

const blockedByAuthority = derivePatternHorizonCompiler({
  ...DIRECT_INPUT,
  observationAuthority: {
    ...READY_AUTHORITY,
    points: [
      {
        pointId: 'center',
        accepted: 0,
        rejected: 1,
        observed: 1,
      },
    ],
    modelSolved: false,
  },
});
assert.deepStrictEqual(blockedByAuthority.authority.decision, {
  kind: 'safe-state',
  reason: 'not-calibrated',
});
assert.strictEqual(blockedByAuthority.selectedWindow, null);
assert.strictEqual(blockedByAuthority.policy, 'hold-safe-state');

const composed = derivePatternHorizonCompiler({
  kind: 'compose',
  generatedAt: '2026-04-11T00:00:00.000Z',
  source: 'test-suite',
  phaseBeat: 0,
  horizonBeats: 3,
  catchToleranceBeats: 0.25,
  observationAuthority: READY_AUTHORITY,
  composition: {
    period: 3,
    seed: 42,
    populationSize: 8,
    generations: 3,
    throwsPerPattern: 6,
    corpus: [
      {
        patternId: 'cascade-3',
        throws: [
          { beat: 0, fromHand: 'right', flightBeats: 3 },
          { beat: 1, fromHand: 'left', flightBeats: 3 },
          { beat: 2, fromHand: 'right', flightBeats: 3 },
        ],
        styleTags: ['basic', 'cascade'],
      },
      {
        patternId: 'shower-3',
        throws: [
          { beat: 0, fromHand: 'right', flightBeats: 5 },
          { beat: 1, fromHand: 'left', flightBeats: 1 },
          { beat: 2, fromHand: 'right', flightBeats: 5 },
        ],
        styleTags: ['shower'],
      },
    ],
  },
});

assert.strictEqual(composed.activePattern.kind, 'compose');
assert.ok(composed.composition !== null);
assert.ok(composed.activePattern.winnerCandidateId !== null);
assert.deepStrictEqual(
  composed.dependentTheoremIds.composition,
  JUGGLING_CHAOS_ORCHESTRATION_THEOREM_IDS
);
assert.ok(composed.selectedWindow !== null);
assert.ok(composed.aggregate.candidateCount > 0);

console.log('pattern-horizon-compiler: all tests passed');
